// File: dns_demo.dart
// Run: dart dns_demo.dart github.com
import 'dart:io';

void main(List<String> args) async {
  final host = args.isNotEmpty ? args[0] : 'example.com';

  print('--- Cold cache lookup ---');
  final t0 = DateTime.now();
  final addrs = await InternetAddress.lookup(host);
  final coldMs = DateTime.now().difference(t0).inMilliseconds;
  print('${addrs.length} address(es) returned in $coldMs ms');
  for (final a in addrs) {
    final kind = a.type == InternetAddressType.IPv4 ? 'A (IPv4)' : 'AAAA (IPv6)';
    print('  $kind : ${a.address}');
  }

  print('\n--- Warm cache lookup ---');
  final t1 = DateTime.now();
  await InternetAddress.lookup(host);
  final warmMs = DateTime.now().difference(t1).inMilliseconds;
  print('Took $warmMs ms  ${warmMs < coldMs ? "(cache hit!)" : ""}');

  print('\n--- Non-existent domain ---');
  try {
    await InternetAddress.lookup('this-does-not-exist-xyz-987.io');
  } on SocketException catch (e) {
    print('Got a SocketException: ${e.message}');
    print('That was NXDOMAIN — DNS said "no such name."');
  }
}

// Typical output:
// --- Cold cache lookup ---
// 4 address(es) returned in 34 ms
//   A (IPv4)    : 140.82.114.4
//   A (IPv4)    : 140.82.113.4
//   AAAA (IPv6) : 2606:50c0:8000::154
//   AAAA (IPv6) : 2606:50c0:8001::154
// --- Warm cache lookup ---
// Took 0 ms  (cache hit!)
// --- Non-existent domain ---
// Got a SocketException: Failed host lookup ...
// That was NXDOMAIN — DNS said "no such name."
